import{_ as n,Z as a,P as d,g as r,k as i,m as o}from"./chunks/framework.Dp5g00Bf.js";const k=JSON.parse('{"title":"markdown语法","description":"","frontmatter":{},"headers":[],"relativePath":"views/1-开发🌏/3-运维/markdown语法/index.md","filePath":"views/1-开发🌏/3-运维/markdown语法/index.md","lastUpdated":1778336291000}'),l={name:"views/1-开发🌏/3-运维/markdown语法/index.md"};function c(p,e,h,u,b,g){const t=a("NolebaseGitContributors"),s=a("NolebaseGitChangelog");return d(),r("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1778336291000"},[e[0]||(e[0]=i('<h1 id="markdown语法" tabindex="-1">markdown语法 <a class="header-anchor" href="#markdown语法" aria-label="Permalink to &quot;markdown语法&quot;">​</a></h1><p>Markdown 是一种轻量级标记语言，它允许人们使用易读易写的纯文本格式编写文档。它的初衷是让大家能更专注于内容，而不是排版。</p><p>以下是 Markdown 最常用的基础语法及其实际用法：</p><hr><h2 id="_1-标题-headings" tabindex="-1">1. 标题 (Headings) <a class="header-anchor" href="#_1-标题-headings" aria-label="Permalink to &quot;1. 标题 (Headings)&quot;">​</a></h2><p>使用 <code>#</code> 号来表示标题，<code>#</code> 的数量代表标题的级别（1-6 级）。</p><blockquote><p><strong>注意：</strong> <code>#</code> 和标题文字之间建议加一个空格。</p></blockquote><p><strong>Markdown</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 一级标题</span></span>\n<span class="line"><span>## 二级标题</span></span>\n<span class="line"><span>### 三级标题</span></span>\n<span class="line"><span>#### 四级标题</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><hr><h2 id="_2-字体格式-emphasis" tabindex="-1">2. 字体格式 (Emphasis) <a class="header-anchor" href="#_2-字体格式-emphasis" aria-label="Permalink to &quot;2. 字体格式 (Emphasis)&quot;">​</a></h2><p>通过星号 <code>*</code> 或下划线 <code>_</code> 来改变文本样式。</p><ul><li><strong>加粗</strong> ：在文字两端各加两个星号 <code>**</code>。</li><li><strong>斜体</strong> ：在文字两端各加一个星号 <code>*</code>。</li><li><strong>斜体加粗</strong> ：在文字两端各加三个星号 <code>***</code>。</li><li><strong>删除线</strong> ：在文字两端各加两个波浪号 <code>~~</code>。</li></ul><p><strong>示例：</strong></p><p><code>**这是粗体**</code> -&gt; <strong>这是粗体</strong></p><p><code>*这是斜体*</code> -&gt; <em>这是斜体</em></p><p><code>~~这是删除线~~</code> -&gt; <s>这是删除线</s></p><hr><h2 id="_3-列表-lists" tabindex="-1">3. 列表 (Lists) <a class="header-anchor" href="#_3-列表-lists" aria-label="Permalink to &quot;3. 列表 (Lists)&quot;">​</a></h2><h3 id="无序列表" tabindex="-1">无序列表 <a class="header-anchor" href="#无序列表" aria-label="Permalink to &quot;无序列表&quot;">​</a></h3><p>使用加号 <code>+</code>、减号 <code>-</code> 或星号 <code>*</code> 后跟空格。</p><ul><li>项目一</li><li>项目二</li></ul><h3 id="有序列表" tabindex="-1">有序列表 <a class="header-anchor" href="#有序列表" aria-label="Permalink to &quot;有序列表&quot;">​</a></h3><p>使用数字加英文句点 <code>.</code> 后跟空格。</p><ol><li>第一步</li><li>第二步</li></ol><hr><h2 id="_4-引用-blockquotes" tabindex="-1">4. 引用 (Blockquotes) <a class="header-anchor" href="#_4-引用-blockquotes" aria-label="Permalink to &quot;4. 引用 (Blockquotes)&quot;">​</a></h2><p>在段落前添加 <code>&gt;</code> 符号。</p><blockquote><p>这是一个引用块。</p><p>它可以包含多行，甚至嵌套。</p></blockquote><hr><h2 id="_5-代码-code" tabindex="-1">5. 代码 (Code) <a class="header-anchor" href="#_5-代码-code" aria-label="Permalink to &quot;5. 代码 (Code)&quot;">​</a></h2><ul><li><strong>行内代码</strong> ：使用反引号 ``` 包裹。</li><li>例如：使用 <code>print()</code> 函数。</li><li><strong>代码块</strong> ：使用三个反引号 ````` 包裹，并可以指定语言进行高亮。</li></ul><p><strong>Python</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>def hello():</span></span>\n<span class="line"><span>    print(&quot;Hello, Markdown!&quot;)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><hr><h2 id="_6-链接与图片-links-images" tabindex="-1">6. 链接与图片 (Links &amp; Images) <a class="header-anchor" href="#_6-链接与图片-links-images" aria-label="Permalink to &quot;6. 链接与图片 (Links &amp; Images)&quot;">​</a></h2><ul><li><strong>超链接</strong> ：<code>[显示文本](链接地址)</code></li><li><code>[百度](https://www.baidu.com)</code></li><li><strong>图片</strong> ：<code>![图片描述](图片地址)</code></li><li><code>![示例图](https://example.com/image.jpg)</code></li></ul><hr><h2 id="_7-分割线与表格-other" tabindex="-1">7. 分割线与表格 (Other) <a class="header-anchor" href="#_7-分割线与表格-other" aria-label="Permalink to &quot;7. 分割线与表格 (Other)&quot;">​</a></h2><h3 id="分割线" tabindex="-1">分割线 <a class="header-anchor" href="#分割线" aria-label="Permalink to &quot;分割线&quot;">​</a></h3><p>使用三个或更多的星号 <code>***</code>、减号 <code>---</code> 或底线 <code>___</code>。</p><hr><h3 id="表格" tabindex="-1">表格 <a class="header-anchor" href="#表格" aria-label="Permalink to &quot;表格&quot;">​</a></h3><p>使用竖线 <code>|</code> 分隔列，使用横线 <code>-</code> 分隔表头和内容。</p><table tabindex="0"><thead><tr><th><strong>姓名</strong></th><th><strong>年龄</strong></th><th><strong>职业</strong></th></tr></thead><tbody><tr><td>张三</td><td>25</td><td>工程师</td></tr><tr><td>李四</td><td>30</td><td>设计师</td></tr></tbody></table><blockquote><p><strong>提示：</strong> <code>:</code> 的位置决定对齐方式（左对齐、居中、右对齐）。</p></blockquote>',46)),o(t),o(s)])}const _=n(l,[["render",c]]);export{k as __pageData,_ as default};
